import { defineSchema, defineTable } from "convex/server";
import { v } from "convex/values";

export default defineSchema({
  messages: defineTable({
    body: v.string(),
    author: v.string(),
    channelId: v.string(),
  }).searchIndex("search_body", {
    searchField: "body",
    filterFields: ["channelId"],
  }),
});

import { mutation, query } from "./_generated/server";
import { v } from "convex/values";
import { paginationOptsValidator } from "convex/server";

export const insert = mutation({
  args: {
    body: v.string(),
    author: v.string(),
    channelId: v.string(),
  },
  handler: async (ctx, args) => {
    return await ctx.db.insert("messages", {
      body: args.body,
      author: args.author,
      channelId: args.channelId,
    });
  },
});

export const search = query({
  args: {
    query: v.string(),
    channelId: v.string(),
    paginationOpts: paginationOptsValidator,
  },
  handler: async (ctx, args) => {
    return await ctx.db
      .query("messages")
      .withSearchIndex("search_body", (q) =>
        q.search("body", args.query).eq("channelId", args.channelId)
      )
      .paginate(args.paginationOpts);
  },
});

const { ConvexHttpClient } = require("convex/browser");

const args = process.argv.slice(2);
const runIdIndex = args.indexOf("--run-id");
if (runIdIndex === -1 || runIdIndex === args.length - 1) {
  console.error("Missing --run-id argument");
  process.exit(1);
}
const runId = args[runIdIndex + 1];

const url = process.env.CONVEX_URL;
if (!url) {
  console.error("Missing CONVEX_URL");
  process.exit(1);
}

const client = new ConvexHttpClient(url);

async function main() {
  await client.mutation("messages:insert", {
    body: "Hello world",
    author: "Alice",
    channelId: runId,
  });
  await client.mutation("messages:insert", {
    body: "Hello Convex",
    author: "Bob",
    channelId: runId,
  });
  await client.mutation("messages:insert", {
    body: "Hello search",
    author: "Charlie",
    channelId: runId,
  });

  let result = null;
  for (let i = 0; i < 20; i++) {
    result = await client.query("messages:search", {
      query: "Hello",
      channelId: runId,
      paginationOpts: { numItems: 2, cursor: null },
    });

    if (result && result.page && result.page.length > 0) {
      break;
    }
    await new Promise((resolve) => setTimeout(resolve, 1000));
  }

  console.log(JSON.stringify(result.page));
}

main().catch(console.error);

